/*
======================================================================
Design System
======================================================================
*/

:root {
    /* Color palette */
    --color-primary-pink: #EC008C;
    --color-primary-teal: #00B3B8;

    --color-secondary-lime: #8DC63F;
    --color-secondary-orange: #F7941D;

    --color-accent-black: #000000;

    --color-neutral-white: #FFFFFF;
    --color-neutral-50: #F5F5F5;
    --color-neutral-200: #E0E0E0;
    --color-neutral-600: #555555;
    --color-neutral-400: #999999;

    --color-success: #4CAF50;
    --color-error: #F44336;
    --color-warning: #FFC107;
    --color-info: #2196F3;

    /* Typography */
    --font-heading: 'Space Grotesk', Helvetica, sans-serif;
    --font-body: 'Source Sans 3', Arial, sans-serif;

    --font-size-h1: 32px;
    --font-size-h2: 24px;
    --font-size-h3: 20px;
    --font-size-body: 15px;
    --font-size-small: 12px;

    --line-height-tight: 1.2;
    --line-height-normal: 1.5;
    --line-height-relaxed: 1.7;

    /* Font weights */
    --weight-light: 300;
    --weight-regular: 400;
    --weight-medium: 500;
    --weight-semibold: 600;
    --weight-bold: 700;

    /* Spacing scale (4px base with emphasis on 8px multiples) */
    --space-0-5: 4px;
    --space-1: 8px;
    --space-2: 16px;
    --space-3: 24px;
    --space-4: 32px;
    --space-5: 48px;
    --space-6: 64px;

    /* Layout */
    --site-max-width: 1120px;

    /* Radius & shadows */
    --radius-sm: 4px;
    --radius-md: 8px;
    --radius-round: 999px;

    --shadow-soft: 0 6px 18px rgba(0, 0, 0, 0.06);
}

/*
======================================================================
Global base styles
======================================================================
*/

*,
*::before,
*::after {
    box-sizing: border-box;
}

html {
    font-size: 100%;
}

body {
    margin: 0;
    min-height: 100vh;
    font-family: var(--font-body);
    font-size: var(--font-size-body);
    line-height: var(--line-height-normal);
    color: var(--color-neutral-600);
    background-color: var(--color-neutral-50);
}

img {
    max-width: 100%;
    height: auto;
    display: block;
}

a {
    color: var(--color-primary-pink);
    text-decoration: none;
    transition: color 150ms ease, text-decoration-color 150ms ease;
}

a:hover,
a:focus-visible {
    color: var(--color-primary-teal);
    text-decoration: underline;
    text-decoration-thickness: 1px;
    text-underline-offset: 2px;
}

button,
input,
select,
textarea {
    font-family: inherit;
}

/*
======================================================================
Layout helpers
======================================================================
*/

.site-main {
    padding: var(--space-4) var(--space-2) var(--space-6);
}

.page-shell {
    max-width: var(--site-max-width);
    margin: 0 auto;
}

.card {
    background-color: var(--color-neutral-white);
    border-radius: var(--radius-md);
    box-shadow: var(--shadow-soft);
    padding: var(--space-4);
}

/* Generic two-column content layout (optional for pages)
   .content-layout {
       display: grid;
       grid-template-columns: minmax(0, 3fr) minmax(260px, 1.3fr);
       gap: var(--space-3);
   }
*/

/*
======================================================================
Header
======================================================================
*/

.site-header {
    background-color: var(--color-neutral-white);
}

.header-inner {
    max-width: var(--site-max-width);
    margin: 0 auto;
    padding: var(--space-3) var(--space-2) 0;
}

/* Logo row */

.header-logo-row {
    display: flex;
    justify-content: center;
}

.site-logo {
    display: inline-flex;
    flex-direction: column;
    align-items: center;
    gap: var(--space-0-5);
    text-align: center;
}

.logo-word {
    font-family: var(--font-heading);
    font-size: 34px;
    font-weight: var(--weight-bold);
    letter-spacing: 0.03em;
}

.logo-word-primary {
    color: var(--color-primary-teal);
}

.logo-word-accent {
    color: var(--color-primary-pink);
}

.logo-tagline {
    font-size: 11px;
    letter-spacing: 0.22em;
    text-transform: uppercase;
    color: var(--color-neutral-400);
}

/* Location row */

.header-location-row {
    margin-top: var(--space-2);
    text-align: center;
}

.location-label {
    font-family: var(--font-heading);
    font-size: 12px;
    letter-spacing: 0.28em;
    text-transform: uppercase;
    color: var(--color-primary-pink);
}

/* Hairline dividers */

.header-divider {
    margin-top: var(--space-3);
    border-bottom: 1px solid var(--color-neutral-200);
}

.header-divider-bottom {
    margin-top: var(--space-1);
}

/* Primary navigation */

.primary-nav {
    display: flex;
    align-items: center;
    margin-top: var(--space-1);
    padding-bottom: var(--space-1);
}

.nav-list {
    display: flex;
    align-items: center;
    justify-content: center;
    flex-wrap: wrap;
    gap: 0;
    list-style: none;
    padding: 0;
    margin: 0;
    flex: 1 1 auto;
}

.nav-item {
    margin: 0 var(--space-2);
}

.nav-link {
    position: relative;
    display: inline-block;
    padding: var(--space-1) 0;
    font-family: var(--font-body);
    font-size: 14px;
    font-weight: var(--weight-regular);
    color: var(--color-accent-black);
    text-decoration: none;
}

.nav-link:hover,
.nav-link:focus-visible {
    color: var(--color-primary-pink);
}

/* Active/current state utility (can be applied server-side) */

.nav-link--current {
    font-weight: var(--weight-semibold);
}

.nav-link--current::after {
    content: '';
    position: absolute;
    left: 0;
    right: 0;
    bottom: -4px;
    height: 2px;
    background-color: var(--color-primary-pink);
}

/* Emphasized nav item with playful underline (memberships) */

.nav-item-emphasis .nav-link {
    font-weight: var(--weight-medium);
}

.nav-item-emphasis .nav-link::after {
    content: '';
    position: absolute;
    left: 4%;
    right: 6%;
    bottom: -6px;
    height: 3px;
    background: repeating-linear-gradient(
        90deg,
        var(--color-accent-black),
        var(--color-accent-black) 7px,
        transparent 7px,
        transparent 12px
    );
    opacity: 0.7;
}

/* Decorative search icon */

.nav-search {
    width: 40px;
    display: flex;
    justify-content: flex-end;
}

.nav-search-icon {
    width: 18px;
    height: 18px;
    border-radius: 50%;
    border: 2px solid var(--color-accent-black);
    position: relative;
}

.nav-search-icon::after {
    content: '';
    position: absolute;
    width: 9px;
    height: 2px;
    background-color: var(--color-accent-black);
    border-radius: 999px;
    transform: rotate(45deg);
    right: -4px;
    bottom: -1px;
}

/* Responsive header adjustments */

@media (max-width: 900px) {
    .header-inner {
        padding-inline: var(--space-2);
    }

    .nav-item {
        margin: 0 var(--space-1);
    }

    .nav-link {
        font-size: 13px;
    }
}

@media (max-width: 640px) {
    .primary-nav {
        flex-wrap: wrap;
    }

    .nav-search {
        order: -1;
        width: auto;
        margin-right: var(--space-1);
    }

    .nav-list {
        justify-content: center;
        margin-top: var(--space-1);
    }
}

/*
======================================================================
Footer
======================================================================
*/

.site-footer {
    border-top: 1px solid var(--color-neutral-200);
    background-color: var(--color-neutral-white);
    padding: var(--space-4) var(--space-2) var(--space-3);
}

.footer-inner {
    max-width: var(--site-max-width);
    margin: 0 auto;
}

.footer-top {
    display: flex;
    flex-wrap: wrap;
    gap: var(--space-4);
    justify-content: space-between;
    align-items: flex-start;
}

.footer-brand {
    flex: 1 1 220px;
}

.footer-logo {
    display: inline-block;
    font-family: var(--font-heading);
    font-size: 22px;
    font-weight: var(--weight-bold);
    color: var(--color-primary-teal);
    letter-spacing: 0.04em;
}

.footer-logo::after {
    content: ' KID';
    font-weight: var(--weight-bold);
    color: var(--color-primary-pink);
}

.footer-tagline {
    margin-top: var(--space-1);
    max-width: 320px;
    font-size: 13px;
    color: var(--color-neutral-400);
}

.footer-links {
    display: flex;
    flex: 2 1 420px;
    gap: var(--space-4);
}

.footer-column {
    flex: 1 1 150px;
}

.footer-heading {
    margin: 0 0 var(--space-1);
    font-family: var(--font-heading);
    font-size: 13px;
    letter-spacing: 0.18em;
    text-transform: uppercase;
    color: var(--color-neutral-600);
}

.footer-list {
    list-style: none;
    padding: 0;
    margin: 0;
}

.footer-link {
    display: inline-block;
    padding: 4px 0;
    font-size: 13px;
    color: var(--color-neutral-600);
}

.footer-link:hover,
.footer-link:focus-visible {
    color: var(--color-primary-pink);
}

.footer-bottom {
    margin-top: var(--space-3);
    padding-top: var(--space-2);
    border-top: 1px solid var(--color-neutral-200);
}

.footer-meta {
    margin: 0;
    font-size: 12px;
    color: var(--color-neutral-400);
}

.footer-year {
    font-variant-numeric: tabular-nums;
}

@media (max-width: 768px) {
    .footer-top {
        flex-direction: column;
    }

    .footer-links {
        flex-wrap: wrap;
    }

    .footer-column {
        flex: 1 1 45%;
    }
}

@media (max-width: 520px) {
    .footer-column {
        flex: 1 1 100%;
    }

    .site-main {
        padding-inline: var(--space-1);
    }

    .card {
        padding: var(--space-3);
    }
}

/*
======================================================================
Form primitives (for future use)
======================================================================
*/

.form-group {
    margin-bottom: var(--space-3);
}

.form-label {
    display: block;
    margin-bottom: 4px;
    font-size: 13px;
    font-weight: var(--weight-medium);
    color: var(--color-neutral-600);
}

.form-control {
    width: 100%;
    padding: 9px 11px;
    border-radius: var(--radius-sm);
    border: 1px solid var(--color-neutral-200);
    background-color: var(--color-neutral-white);
    font-size: 14px;
    transition: border-color 150ms ease, box-shadow 150ms ease;
}

.form-control:focus-visible {
    outline: none;
    border-color: var(--color-primary-pink);
    box-shadow: 0 0 0 1px rgba(236, 0, 140, 0.35);
}
